1	/**
2	 * The Oculus — web dashboard apparatus.
3	 *
4	 * Serves a web dashboard via Hono. Plugins contribute pages as static asset
5	 * directories and custom API routes through kit contributions. Guild tools are
6	 * automatically exposed as REST endpoints.
7	 */
8	
9	import fs from 'node:fs';
10	import path from 'node:path';
11	import { Hono } from 'hono';
12	import { serve } from '@hono/node-server';
13	import type { Server } from 'node:http';
14	import { z } from 'zod';
15	
16	import type { Plugin, StartupContext, LoadedKit, LoadedApparatus } from '@shardworks/nexus-core';
17	import { guild, VERSION } from '@shardworks/nexus-core';
18	import type { InstrumentariumApi } from '@shardworks/tools-apparatus';
19	import { tool } from '@shardworks/tools-apparatus';
20	
21	import type { OculusApi, OculusConfig, OculusKit, PageContribution, RouteContribution } from './types.ts';
22	
23	// ── MIME types ────────────────────────────────────────────────────────
24	
25	const MIME_TYPES: Record<string, string> = {
26	  '.html': 'text/html; charset=utf-8',
27	  '.css': 'text/css; charset=utf-8',
28	  '.js': 'application/javascript; charset=utf-8',
29	  '.mjs': 'application/javascript; charset=utf-8',
30	  '.json': 'application/json; charset=utf-8',
31	  '.png': 'image/png',
32	  '.jpg': 'image/jpeg',
33	  '.jpeg': 'image/jpeg',
34	  '.gif': 'image/gif',
35	  '.svg': 'image/svg+xml',
36	  '.ico': 'image/x-icon',
37	  '.woff': 'font/woff',
38	  '.woff2': 'font/woff2',
39	  '.ttf': 'font/ttf',
40	  '.map': 'application/json',
41	};
42	
43	function getMimeType(filePath: string): string {
44	  const ext = path.extname(filePath).toLowerCase();
45	  return MIME_TYPES[ext] ?? 'application/octet-stream';
46	}
47	
48	// ── Tool→REST mapping helpers ─────────────────────────────────────────
49	
50	export function toolNameToRoute(name: string): string {
51	  const idx = name.indexOf('-');
52	  if (idx === -1) return `/api/${name}`;
53	  return `/api/${name.slice(0, idx)}/${name.slice(idx + 1)}`;
54	}
55	
56	export function permissionToMethod(permission: string | undefined): 'GET' | 'POST' | 'DELETE' {
57	  if (permission === undefined) return 'GET';
58	  const level = permission.includes(':')
59	    ? permission.slice(permission.lastIndexOf(':') + 1)
60	    : permission;
61	  if (level === 'read') return 'GET';
62	  if (level === 'write' || level === 'admin') return 'POST';
63	  if (level === 'delete') return 'DELETE';
64	  return 'POST';
65	}
66	
67	// ── Query param coercion ──────────────────────────────────────────────
68	
69	function isNumberSchema(schema: z.ZodTypeAny): boolean {
70	  let inner: z.ZodTypeAny = schema;
71	  if (inner instanceof z.ZodOptional) inner = inner.unwrap() as z.ZodTypeAny;
72	  if (inner instanceof z.ZodDefault) inner = inner.unwrap() as z.ZodTypeAny;
73	  if (inner instanceof z.ZodOptional) inner = inner.unwrap() as z.ZodTypeAny;
74	  return inner instanceof z.ZodNumber;
75	}
76	
77	function isBooleanSchema(schema: z.ZodTypeAny): boolean {
78	  let inner: z.ZodTypeAny = schema;
79	  if (inner instanceof z.ZodOptional) inner = inner.unwrap() as z.ZodTypeAny;
80	  if (inner instanceof z.ZodDefault) inner = inner.unwrap() as z.ZodTypeAny;
81	  if (inner instanceof z.ZodOptional) inner = inner.unwrap() as z.ZodTypeAny;
82	  return inner instanceof z.ZodBoolean;
83	}
84	
85	export function coerceParams(
86	  shape: Record<string, z.ZodTypeAny>,
87	  params: Record<string, string>,
88	): Record<string, unknown> {
89	  const result: Record<string, unknown> = { ...params };
90	  for (const [key, schema] of Object.entries(shape)) {
91	    const value = result[key];
92	    if (typeof value !== 'string') continue;
93	    if (isNumberSchema(schema)) {
94	      result[key] = Number(value);
95	    } else if (isBooleanSchema(schema)) {
96	      result[key] = value === 'true';
97	    }
98	  }
99	  return result;
100	}
101	
102	// ── Chrome injection ─────────────────────────────────────────────────
103	
104	export function injectChrome(html: string, stylesheetPath: string, navHtml: string): string {
105	  // Check for </head> case-insensitively
106	  const headCloseMatch = html.match(/<\/head>/i);
107	  const bodyOpenMatch = html.match(/<body[^>]*>/i);
108	
109	  // If neither tag present, return unmodified
110	  if (!headCloseMatch && !bodyOpenMatch) return html;
111	
112	  let result = html;
113	
114	  // Insert stylesheet link before </head>
115	  if (headCloseMatch && headCloseMatch.index !== undefined) {
116	    const idx = headCloseMatch.index;
117	    result =
118	      result.slice(0, idx) +
119	      `<link rel="stylesheet" href="${stylesheetPath}">` +
120	      result.slice(idx);
121	  }
122	
123	  // Insert nav after <body...>
124	  // Need to recalculate position after potential head insertion
125	  const bodyMatch = result.match(/<body[^>]*>/i);
126	  if (bodyMatch && bodyMatch.index !== undefined) {
127	    const idx = bodyMatch.index + bodyMatch[0].length;
128	    result = result.slice(0, idx) + navHtml + result.slice(idx);
129	  }
130	
131	  return result;
132	}
133	
134	function buildNavHtml(pages: PageContribution[]): string {
135	  const pageLinks = pages
136	    .map((p) => `<a href="/pages/${p.id}/">${p.title}</a>`)
137	    .join('\n  ');
138	  return `<nav id="oculus-nav">
139	  <a href="/">Guild</a>
140	  ${pageLinks}
141	</nav>`;
142	}
143	
144	// ── HTML escaping ─────────────────────────────────────────────────────
145	
146	function escapeHtml(text: string): string {
147	  return text
148	    .replace(/&/g, '&amp;')
149	    .replace(/</g, '&lt;')
150	    .replace(/>/g, '&gt;');
151	}
152	
153	// ── Tool param extraction (reimplemented from tools-show) ────────────
154	
155	interface ParamInfo {
156	  type: string;
157	  description: string | null;
158	  optional: boolean;
159	}
160	
161	function zodTypeToJsonType(zodType: z.ZodType): string {
162	  if (zodType instanceof z.ZodString) return 'string';
163	  if (zodType instanceof z.ZodNumber) return 'number';
164	  if (zodType instanceof z.ZodBoolean) return 'boolean';
165	  if (zodType instanceof z.ZodArray) return 'array';
166	  if (zodType instanceof z.ZodObject) return 'object';
167	  if (zodType instanceof z.ZodEnum) return 'string';
168	  if (zodType instanceof z.ZodLiteral) return typeof zodType._def.values[0];
169	  if (zodType instanceof z.ZodUnion) return 'union';
170	  if (zodType instanceof z.ZodNullable) return zodTypeToJsonType(zodType.unwrap() as z.ZodType);
171	  return 'unknown';
172	}
173	
174	function extractSingleParam(zodType: z.ZodType): ParamInfo {
175	  let isOptional = false;
176	  let inner: z.ZodType = zodType;
177	
178	  if (inner instanceof z.ZodOptional) {
179	    isOptional = true;
180	    inner = inner.unwrap() as z.ZodType;
181	  }
182	  if (inner instanceof z.ZodDefault) {
183	    isOptional = true;
184	    inner = inner.unwrap() as z.ZodType;
185	  }
186	
187	  return {
188	    type: zodTypeToJsonType(inner),
189	    description: inner.description ?? null,
190	    optional: isOptional,
191	  };
192	}
193	
194	function extractParams(schema: z.ZodObject<z.ZodRawShape>): Record<string, ParamInfo> {
195	  const shape = schema.shape;
196	  const result: Record<string, ParamInfo> = {};
197	  for (const [key, zodType] of Object.entries(shape)) {
198	    result[key] = extractSingleParam(zodType as z.ZodType);
199	  }
200	  return result;
201	}
202	
203	// ── Apparatus factory ─────────────────────────────────────────────────
204	
205	export function createOculus(): Plugin {
206	  let serverPort = 7470;
207	  let server: Server | null = null;
208	  let honoApp: Hono | null = null;
209	
210	  const api: OculusApi = {
211	    port(): number {
212	      return serverPort;
213	    },
214	    startServer(): Promise<void> {
215	      return startServer();
216	    },
217	  };
218	
219	  /** Start the HTTP server (called explicitly via the oculus tool). */
220	  async function startServer(): Promise<void> {
221	    if (server) return; // already running
222	    if (!honoApp) throw new Error('[oculus] Cannot start server — apparatus not initialized');
223	
224	    const app = honoApp;
225	    const port = serverPort;
226	    await new Promise<void>((resolve, reject) => {
227	      server = serve({ fetch: app.fetch, port }, () => {
228	        console.log(`[oculus] Listening on http://localhost:${port}`);
229	        resolve();
230	      }) as Server;
231	      server.on('error', reject);
232	    });
233	  }
234	
235	  return {
236	    apparatus: {
237	      requires: ['tools'],
238	      consumes: ['pages', 'routes'],
239	      provides: api,
240	
241	      async start(ctx: StartupContext): Promise<void> {
242	        const g = guild();
243	        const oculusConfig: OculusConfig = g.guildConfig().oculus ?? {};
244	        serverPort = oculusConfig.port ?? 7470;
245	
246	        const app = new Hono();
247	        honoApp = app;
248	
249	        // Track registered pages and custom route paths
250	        const pages: PageContribution[] = [];
251	        const customRoutePaths = new Set<string>();
252	        const mappedToolRoutes = new Set<string>();
253	
254	        // ── Custom route registration helper ─────────────────────────
255	        function registerCustomRoute(route: RouteContribution, pluginId: string): void {
256	          if (!route.path.startsWith('/api/')) {
257	            console.warn(`[oculus] Custom route "${route.path}" from "${pluginId}" must start with /api/ — skipped`);
258	            return;
259	          }
260	          const method = route.method.toLowerCase() as keyof typeof app;
261	          (app[method] as (path: string, handler: (c: unknown) => unknown) => void)(
262	            route.path,
263	            route.handler as (c: unknown) => unknown,
264	          );
265	          customRoutePaths.add(route.path);
266	        }
267	
268	        // ── Page serving helper ───────────────────────────────────────
269	        function resolveDirForPackage(packageName: string, dir: string): string {
270	          return path.join(g.home, 'node_modules', packageName, dir);
271	        }
272	
273	        function registerPage(page: PageContribution, resolvedDir: string): void {
274	          pages.push({ ...page });
275	
276	          app.get(`/pages/${page.id}/*`, async (c) => {
277	            const requestPath = c.req.path;
278	            const prefix = `/pages/${page.id}/`;
279	            const filePath = requestPath.slice(prefix.length) || 'index.html';
280	
281	            // Prevent directory traversal
282	            if (filePath.includes('..')) {
283	              return c.text('Not found', 404);
284	            }
285	
286	            const absolutePath = path.join(resolvedDir, filePath);
287	
288	            // Ensure file is within resolved dir
289	            if (!absolutePath.startsWith(resolvedDir)) {
290	              return c.text('Not found', 404);
291	            }
292	
293	            try {
294	              const content = fs.readFileSync(absolutePath);
295	              const mimeType = getMimeType(absolutePath);
296	
297	              // Only inject chrome for the root index.html
298	              const isIndexHtml = filePath === 'index.html' || filePath === '';
299	              if (isIndexHtml && mimeType.startsWith('text/html')) {
300	                const html = content.toString('utf-8');
301	                const navHtml = buildNavHtml(pages);
302	                const injected = injectChrome(html, '/static/style.css', navHtml);
303	                return new Response(injected, {
304	                  headers: { 'Content-Type': 'text/html; charset=utf-8' },
305	                });
306	              }
307	
308	              return new Response(content, {
309	                headers: { 'Content-Type': mimeType },
310	              });
311	            } catch {
312	              return c.text('Not found', 404);
313	            }
314	          });
315	        }
316	
317	        // ── Tool route registration helper ───────────────────────────
318	        function registerToolRoute(
319	          toolDef: import('@shardworks/tools-apparatus').ToolDefinition,
320	          instrumentarium: InstrumentariumApi,
321	        ): void {
322	          const routePath = toolNameToRoute(toolDef.name);
323	          const method = permissionToMethod(toolDef.permission);
324	
325	          if (mappedToolRoutes.has(routePath)) return;
326	
327	          if (customRoutePaths.has(routePath)) {
328	            console.warn(
329	              `[oculus] Tool route ${method} ${routePath} conflicts with custom route from plugin — skipped`,
330	            );
331	            return;
332	          }
333	
334	          void instrumentarium; // suppress unused warning
335	
336	          const shape = toolDef.params.shape as Record<string, z.ZodTypeAny>;
337	
338	          if (method === 'GET') {
339	            app.get(routePath, async (c) => {
340	              try {
341	                const rawQuery = c.req.query();
342	                const coerced = coerceParams(shape, rawQuery);
343	                const validated = toolDef.params.parse(coerced);
344	                const result = await toolDef.handler(validated);
345	                return c.json(result);
346	              } catch (err) {
347	                if (err instanceof z.ZodError) {
348	                  return c.json({ error: err.message, details: err.issues }, 400);
349	                }
350	                const message = err instanceof Error ? err.message : String(err);
351	                return c.json({ error: message }, 500);
352	              }
353	            });
354	          } else if (method === 'DELETE') {
355	            app.delete(routePath, async (c) => {
356	              try {
357	                const body = await c.req.json();
358	                const validated = toolDef.params.parse(body);
359	                const result = await toolDef.handler(validated);
360	                return c.json(result);
361	              } catch (err) {
362	                if (err instanceof z.ZodError) {
363	                  return c.json({ error: err.message, details: err.issues }, 400);
364	                }
365	                const message = err instanceof Error ? err.message : String(err);
366	                return c.json({ error: message }, 500);
367	              }
368	            });
369	          } else {
370	            app.post(routePath, async (c) => {
371	              try {
372	                const body = await c.req.json();
373	                const validated = toolDef.params.parse(body);
374	                const result = await toolDef.handler(validated);
375	                return c.json(result);
376	              } catch (err) {
377	                if (err instanceof z.ZodError) {
378	                  return c.json({ error: err.message, details: err.issues }, 400);
379	                }
380	                const message = err instanceof Error ? err.message : String(err);
381	                return c.json({ error: message }, 500);
382	              }
383	            });
384	          }
385	
386	          mappedToolRoutes.add(routePath);
387	        }
388	
389	        // ── Scan contributions from a kit ────────────────────────────
390	        function scanKit(kit: LoadedKit): void {
391	          const oculusKit = kit.kit as OculusKit;
392	
393	          if (oculusKit.routes) {
394	            for (const route of oculusKit.routes) {
395	              registerCustomRoute(route, kit.id);
396	            }
397	          }
398	
399	          if (oculusKit.pages) {
400	            for (const page of oculusKit.pages) {
401	              const resolvedDir = resolveDirForPackage(kit.packageName, page.dir);
402	              registerPage(page, resolvedDir);
403	            }
404	          }
405	        }
406	
407	        function scanApparatus(apparatus: LoadedApparatus): void {
408	          if (!apparatus.apparatus.supportKit) return;
409	          const oculusKit = apparatus.apparatus.supportKit as OculusKit;
410	
411	          if (oculusKit.routes) {
412	            for (const route of oculusKit.routes) {
413	              registerCustomRoute(route, apparatus.id);
414	            }
415	          }
416	
417	          if (oculusKit.pages) {
418	            for (const page of oculusKit.pages) {
419	              const resolvedDir = resolveDirForPackage(apparatus.packageName, page.dir);
420	              registerPage(page, resolvedDir);
421	            }
422	          }
423	        }
424	
425	        // ── Scan existing kits and apparatuses ───────────────────────
426	        for (const kit of g.kits()) {
427	          scanKit(kit);
428	        }
429	        for (const apparatus of g.apparatuses()) {
430	          scanApparatus(apparatus);
431	        }
432	
433	        // ── Register custom routes first ─────────────────────────────
434	        // (already done in scanKit/scanApparatus above)
435	
436	        // ── Register tool routes ─────────────────────────────────────
437	        const instrumentarium = g.apparatus<InstrumentariumApi>('tools');
438	        const allTools = instrumentarium.list();
439	        const patronTools = allTools.filter(
440	          (r) => !r.definition.callableBy || r.definition.callableBy.includes('patron'),
441	        );
442	
443	        for (const resolved of patronTools) {
444	          registerToolRoute(resolved.definition, instrumentarium);
445	        }
446	
447	        // ── GET /api/_status ─────────────────────────────────────────
448	        app.get('/api/_status', (c) => {
449	          const config = g.guildConfig();
450	          return c.json({
451	            guild: config.name,
452	            nexus: VERSION,
453	            home: g.home,
454	            model: config.settings?.model ?? '(not set)',
455	            port: serverPort,
456	            apparatuses: g.apparatuses().map((a) => ({ id: a.id, version: a.version })),
457	            kits: g.kits().map((k) => ({ id: k.id, version: k.version })),
458	            failedPlugins: g.failedPlugins().map((f) => ({ id: f.id, reason: f.reason })),
459	            warnings: g.startupWarnings(),
460	            config: config,
461	          });
462	        });
463	
464	        // ── GET /api/_tools ──────────────────────────────────────────
465	        app.get('/api/_tools', (c) => {
466	          const tools = instrumentarium.list().filter(
467	            (r) => !r.definition.callableBy || r.definition.callableBy.includes('patron'),
468	          );
469	
470	          const entries = tools.map((r) => ({
471	            name: r.definition.name,
472	            route: toolNameToRoute(r.definition.name),
473	            method: permissionToMethod(r.definition.permission),
474	            description: r.definition.description,
475	            params: extractParams(r.definition.params),
476	          }));
477	
478	          return c.json(entries);
479	        });
480	
481	        // ── Static assets ────────────────────────────────────────────
482	        const staticDir = path.join(import.meta.dirname, 'static');
483	        app.get('/static/*', (c) => {
484	          const requestPath = c.req.path;
485	          const filePath = requestPath.slice('/static/'.length);
486	
487	          if (filePath.includes('..')) {
488	            return c.text('Not found', 404);
489	          }
490	
491	          const absolutePath = path.join(staticDir, filePath);
492	          try {
493	            const content = fs.readFileSync(absolutePath);
494	            const mimeType = getMimeType(absolutePath);
495	            return new Response(content, {
496	              headers: { 'Content-Type': mimeType },
497	            });
498	          } catch {
499	            return c.text('Not found', 404);
500	          }
501	        });
502	
503	        // ── Home page ────────────────────────────────────────────────
504	        app.get('/', (c) => {
505	          const config = g.guildConfig();
506	          const guildName = config.name;
507	          const navHtml = buildNavHtml(pages);
508	          const model = config.settings?.model ?? '(not set)';
509	
510	          // ── Identity card ──────────────────────────────────────────
511	          const identityCard = `<div class="card" style="margin-bottom: 16px;">
512	    <h2>Identity</h2>
513	    <table class="data-table">
514	      <tbody>
515	        <tr><td>Guild</td><td>${escapeHtml(guildName)}</td></tr>
516	        <tr><td>Nexus</td><td>${escapeHtml(VERSION)}</td></tr>
517	        <tr><td>Home</td><td>${escapeHtml(g.home)}</td></tr>
518	        <tr><td>Model</td><td>${escapeHtml(model)}</td></tr>
519	        <tr><td>Port</td><td>${serverPort}</td></tr>
520	      </tbody>
521	    </table>
522	  </div>`;
523	
524	          // ── Warnings card (conditional) ────────────────────────────
525	          const warnings = g.startupWarnings();
526	          const warningsCard = warnings.length > 0
527	            ? `<div class="card" style="margin-bottom: 16px;">
528	    <h2>Warnings</h2>
529	    <ul>
530	      ${warnings.map((w) => `<li><span class="badge badge--warning">${escapeHtml(w)}</span></li>`).join('\n      ')}
531	    </ul>
532	  </div>`
533	            : '';
534	
535	          // ── Plugins table ──────────────────────────────────────────
536	          const apparatuses = g.apparatuses();
537	          const kits = g.kits();
538	          const failedPlugins = g.failedPlugins();
539	
540	          let pluginRows = '';
541	          if (apparatuses.length === 0 && kits.length === 0 && failedPlugins.length === 0) {
542	            pluginRows = `<tr><td colspan="4" class="empty-state">No plugins loaded.</td></tr>`;
543	          } else {
544	            pluginRows += apparatuses.map((a) =>
545	              `<tr>
546	          <td>${escapeHtml(a.id)}</td>
547	          <td>apparatus</td>
548	          <td>${escapeHtml(a.version)}</td>
549	          <td><span class="badge badge--success">apparatus</span></td>
550	        </tr>`,
551	            ).join('\n');
552	            pluginRows += kits.map((k) =>
553	              `<tr>
554	          <td>${escapeHtml(k.id)}</td>
555	          <td>kit</td>
556	          <td>${escapeHtml(k.version)}</td>
557	          <td><span class="badge badge--info">kit</span></td>
558	        </tr>`,
559	            ).join('\n');
560	            pluginRows += failedPlugins.map((f) =>
561	              `<tr>
562	          <td>${escapeHtml(f.id)}</td>
563	          <td>—</td>
564	          <td>—</td>
565	          <td><span class="badge badge--error" title="${escapeHtml(f.reason)}">failed</span> <span style="color: var(--text-dim); font-size: 11px;">${escapeHtml(f.reason)}</span></td>
566	        </tr>`,
567	            ).join('\n');
568	          }
569	
570	          const pluginsCard = `<div class="card" style="margin-bottom: 16px;">
571	    <h2>Plugins</h2>
572	    <table class="data-table">
573	      <thead>
574	        <tr><th>Id</th><th>Type</th><th>Version</th><th>Status</th></tr>
575	      </thead>
576	      <tbody>
577	        ${pluginRows}
578	      </tbody>
579	    </table>
580	  </div>`;
581	
582	          // ── Configuration card ─────────────────────────────────────
583	          let rawConfig = '';
584	          try {
585	            rawConfig = fs.readFileSync(path.join(g.home, 'guild.json'), 'utf-8');
586	          } catch {
587	            rawConfig = '(unable to read guild.json)';
588	          }
589	
590	          const configCard = `<div class="card">
591	    <details>
592	      <summary>guild.json</summary>
593	      <pre class="config-block"><code>${escapeHtml(rawConfig)}</code></pre>
594	    </details>
595	  </div>`;
596	
597	          const html = `<!DOCTYPE html>
598	<html lang="en">
599	<head>
600	  <meta charset="UTF-8">
601	  <meta name="viewport" content="width=device-width, initial-scale=1.0">
602	  <title>${escapeHtml(guildName)} — Guild Dashboard</title>
603	  <link rel="stylesheet" href="/static/style.css">
604	</head>
605	<body>
606	${navHtml}
607	<main style="padding: 24px;">
608	  <h1>${escapeHtml(guildName)}</h1>
609	  ${identityCard}
610	  ${warningsCard}
611	  ${pluginsCard}
612	  ${configCard}
613	</main>
614	</body>
615	</html>`;
616	
617	          return c.html(html);
618	        });
619	
620	        // ── Late-arriving plugins ─────────────────────────────────────
621	        ctx.on('plugin:initialized', (plugin: unknown) => {
622	          const loaded = plugin as LoadedApparatus | LoadedKit;
623	          if ('apparatus' in loaded) {
