1	/**
2	 * The Spider — public types.
3	 *
4	 * Rig and engine data model, CrawlResult, SpiderApi, and configuration.
5	 * Engine yield shapes (DraftYields, SealYields) live here too so downstream
6	 * packages can import them without depending on the engine implementation files.
7	 */
8	
9	import type { ZodSchema } from 'zod';
10	
11	// ── Engine instance status ────────────────────────────────────────────
12	
13	export type EngineStatus = 'pending' | 'running' | 'completed' | 'failed' | 'cancelled' | 'blocked';
14	
15	// ── Block record ──────────────────────────────────────────────────────
16	
17	/**
18	 * Persisted record of an active engine block.
19	 * Present on an EngineInstance when status === 'blocked'.
20	 * Cleared when the block is resolved.
21	 */
22	export interface BlockRecord {
23	  /** Block type identifier (matches a registered BlockType.id). */
24	  type: string;
25	  /** Structured condition payload — shape validated by the block type's conditionSchema. */
26	  condition: unknown;
27	  /** ISO timestamp when the engine was blocked. */
28	  blockedAt: string;
29	  /** Optional human-readable message from the engine. */
30	  message?: string;
31	  /** ISO timestamp of the last checker evaluation. Updated on every check cycle. */
32	  lastCheckedAt?: string;
33	}
34	
35	// ── Engine instance ───────────────────────────────────────────────────
36	
37	/**
38	 * A single engine slot within a rig.
39	 *
40	 * `id` is the engine's position identifier (e.g. 'draft', 'implement').
41	 * For the static pipeline it matches `designId`.
42	 *
43	 * `givensSpec` holds literal values set at spawn time (writ, role, commands).
44	 * The Spider assembles `givens` from this directly; upstream yields arrive
45	 * via `context.upstream` as the escape hatch.
46	 */
47	export interface EngineInstance {
48	  /** Unique identifier within the rig (e.g. 'draft', 'implement'). */
49	  id: string;
50	  /** The engine design to look up in the Fabricator. */
51	  designId: string;
52	  /** Current execution status. */
53	  status: EngineStatus;
54	  /** Engine IDs that must be completed before this engine can run. */
55	  upstream: string[];
56	  /** Literal givens values set at rig spawn time. */
57	  givensSpec: Record<string, unknown>;
58	  /** Yields from a completed engine run (JSON-serializable). */
59	  yields?: unknown;
60	  /** Error message if this engine failed. */
61	  error?: string;
62	  /** Session ID from a launched quick engine, used by the collect step. */
63	  sessionId?: string;
64	  /** ISO timestamp when execution started. */
65	  startedAt?: string;
66	  /** ISO timestamp when execution completed (or failed). */
67	  completedAt?: string;
68	  /** Present when status === 'blocked'. Cleared when the block is resolved. */
69	  block?: BlockRecord;
70	}
71	
72	// ── Rig ──────────────────────────────────────────────────────────────
73	
74	export type RigStatus = 'running' | 'completed' | 'failed' | 'blocked';
75	
76	/**
77	 * A rig — the execution context for a single writ.
78	 *
79	 * Stored in The Stacks (`spider/rigs` book). The `engines` array is the
80	 * ordered pipeline of engine instances. The Spider updates this document
81	 * in-place as engines run and complete.
82	 */
83	export interface RigDoc {
84	  /** Index signature required to satisfy BookEntry constraint. */
85	  [key: string]: unknown;
86	  /** Unique rig id. */
87	  id: string;
88	  /** The writ this rig is executing. */
89	  writId: string;
90	  /** Current rig status. */
91	  status: RigStatus;
92	  /** Ordered engine pipeline. */
93	  engines: EngineInstance[];
94	  /** ISO timestamp when the rig was created. */
95	  createdAt: string;
96	  /** Engine id whose yields provide the resolution summary. Set at spawn time. */
97	  resolutionEngineId?: string;
98	}
99	
100	// ── Rig filters ───────────────────────────────────────────────────────
101	
102	/**
103	 * Filters for listing rigs.
104	 */
105	export interface RigFilters {
106	  /** Filter by rig status. */
107	  status?: RigStatus;
108	  /** Maximum number of results (default: 20). */
109	  limit?: number;
110	  /** Number of results to skip. */
111	  offset?: number;
112	}
113	
114	// ── Rig templates ─────────────────────────────────────────────────────
115	
116	/**
117	 * A single engine slot declared in a rig template.
118	 */
119	export interface RigTemplateEngine {
120	  /** Engine id unique within this template. */
121	  id: string;
122	  /** Engine design id to look up in the Fabricator. */
123	  designId: string;
124	  /** Engine ids within this template whose completion is required first. Defaults to []. */
125	  upstream?: string[];
126	  /**
127	   * Givens to pass at spawn time.
128	   * String values starting with '$' (either $name or ${name}) are variable
129	   * references resolved at spawn time:
130	   *   '$writ' or '${writ}' — the WritDoc for this rig's writ
131	   *   '$vars.<key>' or '${vars.<key>}' — value from spider.variables config
132	   * Non-string values are passed through literally.
133	   * Variables that resolve to undefined cause the key to be omitted.
134	   */
135	  givens?: Record<string, unknown>;
136	}
137	
138	/**
139	 * A complete rig template.
140	 */
141	export interface RigTemplate {
142	  /** Ordered list of engine slot declarations. */
143	  engines: RigTemplateEngine[];
144	  /**
145	   * Engine id whose yields provide the writ resolution summary.
146	   * Falls back to seal engine, then last completed engine in array order.
147	   */
148	  resolutionEngine?: string;
149	}
150	
151	// ── CrawlResult ────────────────────────────────────────────────────────
152	
153	/**
154	 * The result of a single crawl() call.
155	 *
156	 * Variants, ordered by priority:
157	 * - 'engine-completed'  — an engine finished (collected or ran inline); rig still running
158	 * - 'engine-started'    — launched a quick engine's session
159	 * - 'engine-blocked'    — engine entered blocked status; rig is still running (other engines active)
160	 * - 'engine-unblocked'  — a blocked engine's condition cleared; engine returned to pending
161	 * - 'rig-spawned'       — created a new rig for a ready writ
162	 * - 'rig-completed'     — the crawl step caused a rig to reach a terminal state
163	 * - 'rig-blocked'       — all forward progress stalled; rig entered blocked status
164	 *
165	 * null means no work was available.
166	 */
167	export type CrawlResult =
168	  | { action: 'engine-completed'; rigId: string; engineId: string }
169	  | { action: 'engine-started'; rigId: string; engineId: string }
170	  | { action: 'engine-blocked'; rigId: string; engineId: string; blockType: string }
171	  | { action: 'engine-unblocked'; rigId: string; engineId: string }
172	  | { action: 'rig-spawned'; rigId: string; writId: string }
173	  | { action: 'rig-completed'; rigId: string; writId: string; outcome: 'completed' | 'failed' }
174	  | { action: 'rig-blocked'; rigId: string; writId: string };
175	
176	// ── Block type ────────────────────────────────────────────────────────
177	
178	/**
179	 * Result of a block type check.
180	 *
181	 * 'cleared' — condition met, unblock the engine.
182	 * 'pending' — condition not yet met, keep polling.
183	 * 'failed'  — condition is permanently unresolvable, fail the engine.
184	 *
185	 * When status is 'failed', an optional reason provides a human-readable
186	 * explanation that the Spider includes in the engine error message.
187	 */
188	export interface CheckResult {
189	  status: 'cleared' | 'pending' | 'failed';
190	  reason?: string;
191	}
192	
193	/** Summary info for a registered block type. */
194	export interface BlockTypeInfo {
195	  /** Block type id. */
196	  id: string;
197	  /** Plugin id that contributed this block type. */
198	  pluginId: string;
199	  /** Suggested poll interval in milliseconds, if set. */
200	  pollIntervalMs?: number;
201	}
202	
203	/**
204	 * A registered block type — defines how to check whether a blocking
205	 * condition has cleared. Contributed via kit/supportKit `blockTypes`.
206	 */
207	export interface BlockType {
208	  /** Unique identifier (e.g. 'writ-status', 'scheduled-time'). */
209	  id: string;
210	  /**
211	   * Check whether the blocking condition has been resolved.
212	   *
213	   * Return { status: 'cleared' } when the condition is met.
214	   * Return { status: 'pending' } when the condition is not yet met.
215	   * Return { status: 'failed' } or { status: 'failed', reason: '...' }
216	   * when the condition is permanently unresolvable.
217	   *
218	   * Throwing is reserved for transient errors (network failures, etc.)
219	   * — the engine stays blocked and the checker is retried next cycle.
220	   */
221	  check: (condition: unknown) => Promise<CheckResult>;
222	  /** Zod schema for validating the condition payload at block time. */
223	  conditionSchema: ZodSchema;
224	  /** Suggested poll interval in milliseconds. If absent, check every crawl cycle. */
225	  pollIntervalMs?: number;
226	}
227	
228	// ── SpiderApi ─────────────────────────────────────────────────────────
229	
230	/**
231	 * The Spider's public API — retrieved via guild().apparatus<SpiderApi>('spider').
232	 */
233	export interface SpiderApi {
234	  /**
235	   * Execute one step of the crawl loop.
236	   *
237	   * Priority ordering: collect > checkBlocked > run > spawn.
238	   * Returns null when no work is available.
239	   */
240	  crawl(): Promise<CrawlResult | null>;
241	
242	  /**
243	   * Show a rig by id. Throws if not found.
244	   */
245	  show(id: string): Promise<RigDoc>;
246	
247	  /**
248	   * List rigs with optional filters, ordered by createdAt descending.
249	   */
250	  list(filters?: RigFilters): Promise<RigDoc[]>;
251	
252	  /**
253	   * Find the rig for a given writ. Returns null if no rig exists.
254	   */
255	  forWrit(writId: string): Promise<RigDoc | null>;
256	
257	  /**
258	   * Manually clear a block on a specific engine, regardless of checker result.
259	   * Throws if the engine is not blocked.
260	   */
261	  resume(rigId: string, engineId: string): Promise<void>;
262	
263	  /**
264	   * Look up a registered block type by ID.
265	   */
266	  getBlockType(id: string): BlockType | undefined;
267	
268	  /**
269	   * List all registered block types with summary info.
270	   */
271	  listBlockTypes(): BlockTypeInfo[];
272	}
273	
274	// ── Configuration ─────────────────────────────────────────────────────
275	
276	/**
277	 * Spider apparatus configuration — lives under the `spider` key in guild.json.
278	 */
279	export interface SpiderConfig {
280	  /**
281	   * Polling interval for crawlContinual tool (milliseconds).
282	   * Default: 5000.
283	   */
284	  pollIntervalMs?: number;
285	  /**
286	   * Build command to pass to quick engines.
287	   */
288	  buildCommand?: string;
289	  /**
290	   * Test command to pass to quick engines.
291	   */
292	  testCommand?: string;
293	  /**
294	   * Named rig templates. Keys are template names (not writ types).
295	   * Templates are looked up by name via rigTemplateMappings.
296	   * A template named 'default' is used as the fallback when no mapping matches.
297	   */
298	  rigTemplates?: Record<string, RigTemplate>;
299	  /**
300	   * Writ type → rig template name mappings.
301	   * 'default' key is the fallback for unmatched writ types.
302	   * Config mappings override kit-contributed mappings for the same writ type.
303	   */
304	  rigTemplateMappings?: Record<string, string>;
305	  /**
306	   * User-defined variables available in rig template givens via '$vars.<key>'.
307	   * Values are passed through literally (string, number, boolean).
308	   * Variables resolving to undefined (key absent) cause the givens key to be omitted.
309	   */
310	  variables?: Record<string, unknown>;
311	}
312	
313	// ── Engine yield shapes ───────────────────────────────────────────────
314	
315	/**
316	 * Yields from the `draft` clockwork engine.
317	 * The Spider stores these in the engine instance and passes them
318	 * to downstream engines via context.upstream['draft'].
319	 */
320	export interface DraftYields {
321	  /** The draft's unique id. */
322	  draftId: string;
323	  /** Codex this draft belongs to. */
324	  codexName: string;
325	  /** Git branch name for the draft. */
326	  branch: string;
327	  /** Absolute filesystem path to the draft's worktree. */
328	  path: string;
329	  /** HEAD commit SHA at the time the draft was opened. Used by review engine to compute diffs. */
330	  baseSha: string;
331	}
332	
333	/**
334	 * Yields from the `seal` clockwork engine.
335	 */
336	export interface SealYields {
337	  /** The commit SHA at head of the target branch after sealing. */
338	  sealedCommit: string;
339	  /** Git strategy used. */
340	  strategy: 'fast-forward' | 'rebase';
341	  /** Number of retry attempts. */
342	  retries: number;
343	  /** Number of inscriptions (commits) sealed. */
344	  inscriptionsSealed: number;
345	}
346	
347	/**
348	 * Yields from the `implement` quick engine.
349	 * Set by the Spider's collect step when the Animator session completes.
350	 */
351	export interface ImplementYields {
352	  /** The Animator session id. */
353	  sessionId: string;
354	  /** Terminal status of the session. */
355	  sessionStatus: 'completed' | 'failed';
356	}
357	
358	/**
359	 * A single mechanical check (build or test) run by the review engine
360	 * before launching the reviewer session.
361	 */
362	export interface MechanicalCheck {
363	  /** Check name. */
364	  name: 'build' | 'test';
365	  /** Whether the command exited with code 0. */
366	  passed: boolean;
367	  /** Combined stdout+stderr, truncated to 4KB. */
368	  output: string;
369	  /** Wall-clock duration of the check in milliseconds. */
370	  durationMs: number;
371	}
372	
373	/**
374	 * Yields from the `review` quick engine.
375	 * Assembled by the Spider's collect step from session.output and session.metadata.
376	 */
377	export interface ReviewYields {
378	  /** The Animator session id. */
379	  sessionId: string;
380	  /** Reviewer's overall assessment — true if the review passed. */
381	  passed: boolean;
382	  /** Structured markdown findings from the reviewer's final message. */
383	  findings: string;
384	  /** Mechanical check results run before the reviewer session. */
385	  mechanicalChecks: MechanicalCheck[];
386	}
387	
388	/**
389	 * Yields from the `revise` quick engine.
390	 * Set by the Spider's collect step when the Animator session completes.
391	 */
392	export interface ReviseYields {
393	  /** The Animator session id. */
394	  sessionId: string;
395	  /** Terminal status of the session. */
396	  sessionStatus: 'completed' | 'failed';
397	}
398	
399	// ── Input request types ──────────────────────────────────────────────
400	
401	export type InputRequestStatus = 'pending' | 'completed' | 'rejected';
402	
403	export interface ChoiceQuestionSpec {
404	  type: 'choice';
405	  /** Human-readable question text. */
406	  label: string;
407	  /** Key → display label options map. */
408	  options: Record<string, string>;
409	  /** When true, the patron can supply a freeform answer instead of selecting. */
410	  allowCustom: boolean;
411	}
412	
413	export interface BooleanQuestionSpec {
414	  type: 'boolean';
415	  /** Human-readable question text. */
416	  label: string;
417	}
418	
419	export interface TextQuestionSpec {
420	  type: 'text';
421	  /** Human-readable question text. */
422	  label: string;
423	}
424	
425	export type QuestionSpec = ChoiceQuestionSpec | BooleanQuestionSpec | TextQuestionSpec;
426	
427	/** Discriminated choice answer — selected from options or freeform custom. */
428	export type ChoiceAnswer = { selected: string } | { custom: string };
429	
430	/**
431	 * Answer value union. Runtime type is determined by the corresponding QuestionSpec:
432	 * - choice → ChoiceAnswer (object with 'selected' or 'custom' key)
433	 * - boolean → boolean
434	 * - text → string
435	 */
436	export type AnswerValue = ChoiceAnswer | boolean | string;
437	
438	/**
439	 * An input request document stored in the spider/input-requests book.
440	 * Created by engines before blocking; answered by patrons via CLI tools.
441	 */
442	export interface InputRequestDoc {
443	  [key: string]: unknown;
444	  /** Unique ID via generateId('ir', 4). */
445	  id: string;
446	  /** Rig this request belongs to. */
447	  rigId: string;
448	  /** Engine that created this request. */
449	  engineId: string;
450	  /** Request lifecycle status. */
451	  status: InputRequestStatus;
452	  /** Optional human-readable context from the engine. */
453	  message?: string;
454	  /** Question key → question spec. */
455	  questions: Record<string, QuestionSpec>;
456	  /** Question key → answer value. Partially filled until completion. */
457	  answers: Record<string, AnswerValue>;
458	  /** Set when status transitions to 'rejected'. */
459	  rejectionReason?: string;
460	  /** ISO timestamp when the request was created. */
461	  createdAt: string;
462	  /** ISO timestamp of the last mutation. */
463	  updatedAt: string;
464	}
465	
466	// Augment GuildConfig so `guild().guildConfig().spider` is typed.
467	declare module '@shardworks/nexus-core' {
468	  interface GuildConfig {
469	    spider?: SpiderConfig;
470	  }
471	}
472

