/* Spider page — page-specific styles */
/* Uses CSS custom properties from the shared Oculus stylesheet */

/* ── Tab bar ─────────────────────────────────────────────────────────── */

.tab-bar {
  display: flex;
  gap: 4px;
  margin-bottom: 16px;
  border-bottom: 1px solid var(--border, #333);
  padding-bottom: 0;
}

.tab {
  background: none;
  border: none;
  border-bottom: 2px solid transparent;
  color: var(--text-dim, #888);
  cursor: pointer;
  font-size: 14px;
  font-weight: 500;
  margin-bottom: -1px;
  padding: 8px 16px;
  transition: color 0.15s, border-color 0.15s;
}

.tab:hover {
  color: var(--text, #eee);
}

.tab.active {
  border-bottom-color: var(--cyan, #0ff);
  color: var(--cyan, #0ff);
}

/* ── Toolbar ─────────────────────────────────────────────────────────── */

.toolbar {
  display: flex;
  align-items: center;
  flex-wrap: wrap;
  gap: 8px;
  margin-bottom: 12px;
}

.toolbar select,
.toolbar input[type="text"],
.toolbar input[type="date"] {
  background: var(--surface, #1a1a1a);
  border: 1px solid var(--border, #333);
  border-radius: 4px;
  color: var(--text, #eee);
  font-size: 13px;
  padding: 5px 8px;
}

.toolbar label {
  align-items: center;
  color: var(--text-dim, #888);
  display: flex;
  font-size: 13px;
  gap: 6px;
}

/* ── Pipeline visualization ──────────────────────────────────────────── */

.pipeline {
  align-items: center;
  display: flex;
  flex-direction: row;
  flex-wrap: wrap;
  gap: 0;
  margin: 12px 0;
  min-height: 72px;
  overflow-x: auto;
  padding: 8px 0;
}

.pipeline-node {
  align-items: center;
  background: var(--surface, #1a1a1a);
  border: 1px solid var(--border, #333);
  border-radius: 6px;
  cursor: pointer;
  display: flex;
  flex-direction: column;
  gap: 4px;
  min-width: 100px;
  padding: 10px 14px;
  position: relative;
  transition: border-color 0.15s, background 0.15s;
  user-select: none;
}

.pipeline-node:hover {
  border-color: var(--cyan, #0ff);
}

.pipeline-node.selected {
  border-color: var(--cyan, #0ff);
  box-shadow: 0 0 0 2px color-mix(in srgb, var(--cyan, #0ff) 30%, transparent);
}

.pipeline-node .node-id {
  color: var(--text, #eee);
  font-family: monospace;
  font-size: 13px;
  font-weight: 600;
}

.pipeline-arrow {
  align-items: center;
  color: var(--text-dim, #888);
  display: flex;
  flex-shrink: 0;
  font-size: 18px;
  padding: 0 4px;
}

/* ── Engine detail panel ─────────────────────────────────────────────── */

.engine-detail-field {
  display: grid;
  gap: 4px 12px;
  grid-template-columns: 140px 1fr;
  margin-bottom: 8px;
}

