/* Oculus shared stylesheet — Tokyo Night palette */

/* ── Custom properties ───────────────────────────────────────────── */
:root {
  --bg: #1a1b26;
  --surface: #24283b;
  --surface2: #2f3549;
  --border: #3b4261;
  --text: #c0caf5;
  --text-dim: #565f89;
  --text-bright: #e0e6ff;
  --green: #9ece6a;
  --red: #f7768e;
  --yellow: #e0af68;
  --cyan: #7dcfff;
  --magenta: #bb9af7;
  --blue: #7aa2f7;
  --font-mono: "SF Mono", "Fira Code", "JetBrains Mono", monospace;
}

/* ── Element-type selectors ──────────────────────────────────────── */
body {
  background: var(--bg);
  color: var(--text);
  font-family: var(--font-mono);
  font-size: 13px;
  line-height: 1.6;
  margin: 0;
  padding: 0;
}

h1, h2, h3, h4 {
  color: var(--text-bright);
  font-weight: 600;
}

a {
  color: var(--cyan);
  text-decoration: none;
}

a:hover {
  text-decoration: underline;
}

table {
  width: 100%;
  border-collapse: collapse;
}

th, td {
  text-align: left;
  padding: 8px;
  border-bottom: 1px solid var(--border);
}

th {
  color: var(--text-dim);
  font-weight: 500;
}

button {
  background: var(--blue);
  color: var(--bg);
  border: none;
  border-radius: 6px;
  padding: 8px 16px;
  cursor: pointer;
  font-family: var(--font-mono);
  font-size: 13px;
}

button:hover {
  opacity: 0.9;
}

input, select, textarea {
  background: var(--surface);
  color: var(--text);
  border: 1px solid var(--border);
  border-radius: 4px;
  padding: 6px 10px;
  font-family: var(--font-mono);
  font-size: 13px;
  outline: none;
}

input:focus, select:focus, textarea:focus {
  border-color: var(--cyan);
}

pre, code {
  background: var(--surface);
  border-radius: 4px;
}

code {
  padding: 2px 6px;
}

pre {
  padding: 16px;
  overflow-x: auto;
}

pre code {
  background: none;
  padding: 0;
  border-radius: 0;
}

/* ── Utility classes ─────────────────────────────────────────────── */
#oculus-nav {
  display: flex;
  gap: 16px;
  align-items: center;
  padding: 8px 16px;
  background: var(--surface);
  border-bottom: 1px solid var(--border);
}

#oculus-nav a {
  color: var(--text-dim);
  font-size: 12px;
  text-decoration: none;
}

#oculus-nav a:hover,
#oculus-nav a:active {
  color: var(--text);
  text-decoration: none;
}

.card {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 16px;
}

.badge {
  display: inline-block;
  font-size: 11px;
  padding: 2px 8px;
  border-radius: 4px;
  background: var(--surface2);
  color: var(--text-dim);
}

.badge--success {
  background: rgba(158, 206, 106, 0.15);
  color: var(--green);
}

.badge--error {
  background: rgba(247, 118, 142, 0.15);
  color: var(--red);
}

.badge--warning {
  background: rgba(224, 175, 104, 0.15);
  color: var(--yellow);
}

.badge--info {
  background: rgba(125, 207, 255, 0.15);
  color: var(--cyan);
}

.badge--active {
  background: rgba(125, 207, 255, 0.15);
  color: var(--cyan);
  animation: pulse 2s infinite;
}

.data-table {
  width: 100%;
  border-collapse: collapse;
}

.data-table tr:nth-child(even) {
  background: rgba(47, 53, 73, 0.3);
}

.btn {
  border: none;
  border-radius: 6px;
  padding: 8px 16px;
  cursor: pointer;
  font-family: var(--font-mono);
  font-size: 13px;
}

.btn--primary {
  background: var(--blue);
  color: var(--bg);
}

.btn--success {
  background: var(--green);
  color: var(--bg);
}

.btn--danger {
  background: var(--red);
  color: var(--bg);
}

.toolbar {
  display: flex;
  gap: 8px;
  align-items: center;
  padding: 8px 0;
}

.empty-state {
  text-align: center;
  padding: 48px 16px;
  color: var(--text-dim);
}

@keyframes pulse {
  0%, 100% { opacity: 1; }
  50% { opacity: 0.6; }
}

/* ── Config display ──────────────────────────────────────────────── */
.config-block {
  max-height: 400px;
  overflow-y: auto;
  margin: 0;
}

details summary {
  cursor: pointer;
  color: var(--text-dim);
  font-size: 13px;
  padding: 4px 0;
}

details summary:hover {
  color: var(--text);
}

details[open] summary {
  margin-bottom: 8px;
}

