1	/**
2	 * Claude Code Session Provider
3	 *
4	 * Apparatus plugin that implements AnimatorSessionProvider for the
5	 * Claude Code CLI. The Animator discovers this via guild config:
6	 *
7	 *   guild.json["animator"]["sessionProvider"] = "claude-code"
8	 *
9	 * Launches sessions via the `claude` CLI in autonomous mode (--print)
10	 * with --output-format stream-json for structured telemetry.
11	 *
12	 * Key design choice: uses async spawn() instead of spawnSync().
13	 * This is required for stream-json transcript parsing, timeout enforcement,
14	 * and future concurrent session support.
15	 */
16	
17	import { spawn } from 'node:child_process';
18	import fs from 'node:fs';
19	import os from 'node:os';
20	import path from 'node:path';
21	
22	import type { Plugin } from '@shardworks/nexus-core';
23	import type {
24	  AnimatorSessionProvider,
25	  SessionProviderConfig,
26	  SessionProviderResult,
27	  SessionChunk,
28	} from '@shardworks/animator-apparatus';
29	
30	import { startMcpHttpServer } from './mcp-server.ts';
31	import type { McpHttpHandle } from './mcp-server.ts';
32	
33	// ── Session File Preparation ────────────────────────────────────────────
34	
35	/** Prepared session files in a temp directory. */
36	interface PreparedSession {
37	  tmpDir: string;
38	  args: string[];
39	  /** If an MCP server was started, this handle closes it. */
40	  mcpHandle?: McpHttpHandle;
41	}
42	
43	/**
44	 * Prepare session files and build base CLI args.
45	 *
46	 * Writes system prompt to a temp directory. Builds the base args array
47	 * including --resume support. When tools are provided, starts an
48	 * in-process MCP HTTP server and writes --mcp-config.
49	 *
50	 * Caller is responsible for cleaning up tmpDir and calling mcpHandle.close().
51	 */
52	async function prepareSession(config: SessionProviderConfig): Promise<PreparedSession> {
53	  const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'nsg-session-'));
54	
55	  const args: string[] = [
56	    '--setting-sources', 'user',
57	    '--dangerously-skip-permissions',
58	    '--model', config.model,
59	  ];
60	
61	  if (config.systemPrompt) {
62	    const systemPromptPath = path.join(tmpDir, 'system-prompt.md');
63	    fs.writeFileSync(systemPromptPath, config.systemPrompt);
64	    args.push('--system-prompt-file', systemPromptPath);
65	  }
66	
67	  // Resume an existing conversation
68	  if (config.conversationId) {
69	    args.push('--resume', config.conversationId);
70	  }
71	
72	  // Tool-equipped session: start MCP HTTP server, write --mcp-config
73	  let mcpHandle: McpHttpHandle | undefined;
74	
75	  if (config.tools && config.tools.length > 0) {
76	    const tools = config.tools.map((rt) => rt.definition);
77	    mcpHandle = await startMcpHttpServer(tools);
78	
79	    const mcpConfig = {
80	      mcpServers: {
81	        'nexus-guild': {
82	          type: 'sse',
83	          url: mcpHandle.url,
84	        },
85	      },
86	    };
87	
88	    const mcpConfigPath = path.join(tmpDir, 'mcp-config.json');
89	    fs.writeFileSync(mcpConfigPath, JSON.stringify(mcpConfig));
90	    args.push('--mcp-config', mcpConfigPath, '--strict-mcp-config');
91	  }
92	
93	  return { tmpDir, args, mcpHandle };
94	}
95	
96	// ── Output extraction ───────────────────────────────────────────────
97	
98	/**
99	 * Extract the final assistant text from a transcript.
100	 *
101	 * Walks the transcript backwards to find the last `assistant` message
102	 * and concatenates its text content blocks.
103	 *
104	 * @internal Exported for testing only.
105	 */
106	export function extractFinalAssistantText(transcript: Record<string, unknown>[]): string | undefined {
107	  for (let i = transcript.length - 1; i >= 0; i--) {
108	    const msg = transcript[i]!;
109	    if (msg.type !== 'assistant') continue;
110	
111	    const message = msg.message as Record<string, unknown> | undefined;
112	    const content = message?.content as Array<Record<string, unknown>> | undefined;
113	    if (!content) continue;
114	
115	    const text = content
116	      .filter((block) => block.type === 'text' && typeof block.text === 'string')
117	      .map((block) => block.text as string)
118	      .join('');
119	
120	    return text || undefined;
121	  }
122	  return undefined;
123	}
124	
125	// ── Result builder ──────────────────────────────────────────────────
126	
127	function buildResult(raw: StreamJsonResult): SessionProviderResult {
128	  const status = raw.exitCode === 0 ? 'completed' as const : 'failed' as const;
129	  return {
130	    status,
131	    exitCode: raw.exitCode,
132	    error: status === 'failed' ? `claude exited with code ${raw.exitCode}` : undefined,
133	    costUsd: raw.costUsd,
134	    tokenUsage: raw.tokenUsage,
135	    providerSessionId: raw.providerSessionId,
136	    transcript: raw.transcript,
137	    output: extractFinalAssistantText(raw.transcript),
138	  };
139	}
140	
141	// ── Provider implementation ──────────────────────────────────────────
142	
143	const provider: AnimatorSessionProvider = {
144	  name: 'claude-code',
145	
146	  launch(config: SessionProviderConfig): {
147	    chunks: AsyncIterable<SessionChunk>;
148	    result: Promise<SessionProviderResult>;
149	  } {
150	    // prepareSession is async (MCP server start), so we wrap the launch
151	    // in a promise. The chunks iterable bridges the async gap — it waits
152	    // for prep to complete before yielding.
153	
154	    let chunkResolve: (() => void) | null = null;
155	    let innerChunks: AsyncIterable<SessionChunk> | null = null;
156	    let innerIterator: AsyncIterator<SessionChunk> | null = null;
157	    let prepDone = false;
158	    let prepError: Error | null = null;
159	    let done = false;
160	
161	    const result = prepareSession(config).then(async ({ tmpDir, args, mcpHandle }) => {
162	      // Autonomous mode: prompt piped via stdin (--print - reads from stdin).
163	      // This avoids Commander parsing issues when the prompt starts with '-'
164	      // (e.g. YAML frontmatter '---') and also avoids OS arg length limits.
165	      const prompt = config.initialPrompt ?? '';
166	      args.push(
167	        '--print', '-',
168	        '--output-format', 'stream-json',
169	        '--verbose',
170	      );
171	
172	      const cleanup = async () => {
173	        await mcpHandle?.close().catch(() => {});
174	        fs.rmSync(tmpDir, { recursive: true, force: true });
175	      };
176	
177	      try {
178	        if (config.streaming) {
179	          const spawned = spawnClaudeStreamingJson(args, config.cwd, config.environment, prompt);
180	          innerChunks = spawned.chunks;
181	          prepDone = true;
182	          if (chunkResolve) { chunkResolve(); chunkResolve = null; }
183	
184	          const raw = await spawned.result;
185	          await cleanup();
186	          return buildResult(raw);
187	        }
188	
189	        // Non-streaming
190	        prepDone = true;
191	        done = true;
192	        if (chunkResolve) { chunkResolve(); chunkResolve = null; }
193	
194	        const raw = await spawnClaudeStreamJson(args, config.cwd, config.environment, prompt);
195	        await cleanup();
196	        return buildResult(raw);
197	      } catch (err) {
198	        await cleanup();
199	        throw err;
200	      }
201	    }).catch((err) => {
202	      // If prep itself failed, unblock the chunk iterator
203	      prepError = err instanceof Error ? err : new Error(String(err));
204	      prepDone = true;
205	      done = true;
206	      if (chunkResolve) { chunkResolve(); chunkResolve = null; }
207	      throw err;
208	    });
209	
210	    // Chunks iterable that bridges the async prep gap. In non-streaming
211	    // mode or on error, it completes immediately with no items.
212	    const chunks: AsyncIterable<SessionChunk> = {
213	      [Symbol.asyncIterator]() {
214	        return {
215	          async next(): Promise<IteratorResult<SessionChunk>> {
216	            // Wait for prep to complete
217	            while (!prepDone) {
218	              await new Promise<void>((resolve) => { chunkResolve = resolve; });
219	            }
220	
221	            if (prepError || done) {
222	              return { value: undefined as unknown as SessionChunk, done: true };
223	            }
224	
225	            // Delegate to inner streaming iterator
226	            if (innerChunks && !innerIterator) {
227	              innerIterator = innerChunks[Symbol.asyncIterator]();
228	            }
229	
230	            if (innerIterator) {
231	              return innerIterator.next();
232	            }
233	
234	            return { value: undefined as unknown as SessionChunk, done: true };
235	          },
236	        };
237	      },
238	    };
239	
240	    return { chunks, result };
241	  },
242	};
243	
244	// ── Apparatus export ─────────────────────────────────────────────────
245	
246	/**
247	 * Create the Claude Code session provider apparatus.
248	 *
249	 * The apparatus has no startup logic — it just provides the
250	 * AnimatorSessionProvider implementation. The Animator looks it up
251	 * via guild().apparatus('claude-code').
252	 */
253	export function createClaudeCodeProvider(): Plugin {
254	  return {
255	    apparatus: {
256	      requires: [],
257	      provides: provider,
258	
259	      start() {
260	        // No startup work — the provider is stateless.
261	      },
262	    },
263	  };
264	}
265	
266	export default createClaudeCodeProvider();
267	
268	// ── MCP server re-exports ───────────────────────────────────────────
269	// The MCP server module is used by the session provider to attach tools
270	// to sessions via --mcp-config, and can be imported directly for
271	// testing or custom integrations.
272	
273	export { createMcpServer, startMcpHttpServer } from './mcp-server.ts';
274	export type { McpHttpHandle } from './mcp-server.ts';
275	
276	// ── Spawn helpers ────────────────────────────────────────────────────
277	
278	/** Parsed result from stream-json output. @internal */
279	export interface StreamJsonResult {
280	  exitCode: number;
281	  transcript: Record<string, unknown>[];
282	  costUsd?: number;
283	  tokenUsage?: {
284	    inputTokens: number;
285	    outputTokens: number;
286	    cacheReadTokens?: number;
287	    cacheWriteTokens?: number;
288	  };
289	  providerSessionId?: string;
290	}
291	
292	/**
293	 * Parse a single NDJSON message from stream-json output.
294	 *
295	 * Returns parsed chunks for streaming and accumulates data into the
296	 * provided accumulators (transcript, metrics).
297	 *
298	 * @internal Exported for testing only.
299	 */
300	export function parseStreamJsonMessage(
301	  msg: Record<string, unknown>,
302	  acc: {
303	    transcript: Record<string, unknown>[];
304	    costUsd?: number;
305	    tokenUsage?: StreamJsonResult['tokenUsage'];
306	    providerSessionId?: string;
307	  },
308	): SessionChunk[] {
309	  const chunks: SessionChunk[] = [];
310	
311	  if (msg.type === 'assistant') {
312	    acc.transcript.push(msg);
313	
314	    const message = msg.message as Record<string, unknown> | undefined;
315	    if (message) {
316	      const content = message.content as Array<Record<string, unknown>> | undefined;
317	      if (content) {
318	        for (const block of content) {
319	          if (block.type === 'text' && typeof block.text === 'string') {
320	            process.stderr.write(block.text);
321	            chunks.push({ type: 'text', text: block.text });
322	          } else if (block.type === 'tool_use' && typeof block.name === 'string') {
323	            chunks.push({ type: 'tool_use', tool: block.name });
324	          }
325	        }
326	      }
327	    }
328	  } else if (msg.type === 'user') {
329	    acc.transcript.push(msg);
330	
331	    const content = (msg as Record<string, unknown>).content as Array<Record<string, unknown>> | undefined;
332	    if (content) {
333	      for (const block of content) {
334	        if (block.type === 'tool_result' && typeof block.tool_use_id === 'string') {
335	          chunks.push({ type: 'tool_result', tool: String(block.tool_use_id) });
336	        }
337	      }
338	    }
339	  } else if (msg.type === 'result') {
340	    acc.costUsd = typeof msg.total_cost_usd === 'number' ? msg.total_cost_usd : undefined;
341	    acc.providerSessionId = typeof msg.session_id === 'string' ? msg.session_id : undefined;
342	
343	    const usage = msg.usage as Record<string, unknown> | undefined;
344	    if (usage) {
345	      acc.tokenUsage = {
346	        inputTokens: (typeof usage.input_tokens === 'number' ? usage.input_tokens : 0),
347	        outputTokens: (typeof usage.output_tokens === 'number' ? usage.output_tokens : 0),
348	        cacheReadTokens: typeof usage.cache_read_input_tokens === 'number'
349	          ? usage.cache_read_input_tokens : undefined,
350	        cacheWriteTokens: typeof usage.cache_creation_input_tokens === 'number'
351	          ? usage.cache_creation_input_tokens : undefined,
352	      };
353	    }
354	  }
355	
356	  return chunks;
357	}
358	
359	/**
360	 * Process NDJSON buffer, calling handler for each complete line.
361	 * Returns the remaining incomplete buffer.
362	 *
363	 * @internal Exported for testing only.
364	 */
365	export function processNdjsonBuffer(
366	  buffer: string,
367	  handler: (msg: Record<string, unknown>) => void,
368	): string {
369	  let newlineIdx: number;
370	  while ((newlineIdx = buffer.indexOf('\n')) !== -1) {
371	    const line = buffer.slice(0, newlineIdx).trim();
372	    buffer = buffer.slice(newlineIdx + 1);
373	
374	    if (!line) continue;
375	
376	    try {
377	      const msg = JSON.parse(line) as Record<string, unknown>;
378	      handler(msg);
379	    } catch {
380	      // Non-JSON line — ignore
381	    }
382	  }
383	  return buffer;
384	}
385	
386	/**
387	 * Spawn Claude in autonomous mode with --output-format stream-json.
388	 *
389	 * Captures stdout (NDJSON lines), parses each line to extract:
390	 * - assistant messages → transcript
391	 * - result message → cost, token usage, session ID
392	 *
393	 * Forwards assistant text content to stderr so it's visible during execution.
394	 */
395	function spawnClaudeStreamJson(args: string[], cwd: string, env?: Record<string, string>, stdinData?: string): Promise<StreamJsonResult> {
396	  return new Promise((resolve, reject) => {
397	    const proc = spawn('claude', args, {
398	      cwd,
399	      stdio: ['pipe', 'pipe', 'inherit'],
400	      env: { ...process.env, ...env },
401	    });
402	
403	    // Pipe prompt via stdin (--print - reads from stdin)
404	    if (stdinData !== undefined) {
405	      proc.stdin!.write(stdinData);
406	      proc.stdin!.end();
407	    }
408	
409	    const acc: {
410	      transcript: Record<string, unknown>[];
411	      costUsd?: number;
412	      tokenUsage?: StreamJsonResult['tokenUsage'];
413	      providerSessionId?: string;
414	    } = { transcript: [] };
415	
416	    let buffer = '';
417	
418	    proc.stdout!.on('data', (chunk: Buffer) => {
419	      buffer += chunk.toString();
420	      buffer = processNdjsonBuffer(buffer, (msg) => {
421	        parseStreamJsonMessage(msg, acc);
422	      });
423	    });
424	
425	    proc.on('error', (err) => {
426	      reject(new Error(`Failed to spawn claude: ${err.message}`));
427	    });
428	
429	    proc.on('close', (code) => {
430	      if (acc.transcript.length > 0) {
431	        process.stderr.write('\n');
432	      }
433	
434	      resolve({
435	        exitCode: code ?? 1,
436	        transcript: acc.transcript,
