1	/**
2	 * Implement engine — quick (Animator-backed).
3	 *
4	 * Summons an anima to do the commissioned work. Wraps the writ body with
5	 * a commit instruction, then calls animator.summon() with the draft
6	 * worktree as the working directory. Returns `{ status: 'launched', sessionId }`
7	 * so the Spider's collect step can poll for completion on subsequent walks.
8	 */
9	
10	import { guild } from '@shardworks/nexus-core';
11	import type { EngineDesign } from '@shardworks/fabricator-apparatus';
12	import type { AnimatorApi } from '@shardworks/animator-apparatus';
13	import type { WritDoc } from '@shardworks/clerk-apparatus';
14	import type { DraftYields } from '../types.ts';
15	
16	const implementEngine: EngineDesign = {
17	  id: 'implement',
18	
19	  async run(givens, context) {
20	    const animator = guild().apparatus<AnimatorApi>('animator');
21	    const writ = givens.writ as WritDoc;
22	    const draft = context.upstream['draft'] as DraftYields;
23	
24	    const prompt = `${writ.body}\n\nCommit all changes before ending your session.`;
25	
26	    const handle = animator.summon({
27	      role: givens.role as string,
28	      prompt,
29	      cwd: draft.path,
30	      environment: { GIT_AUTHOR_EMAIL: `${writ.id}@nexus.local` },
31	      metadata: { engineId: context.engineId, writId: writ.id },
32	    });
33	
34	    return { status: 'launched', sessionId: handle.sessionId };
35	  },
36	};
37	
38	export default implementEngine;
39

